uit": "Golden flesh with honey-like sweetness. Peachy interior, soft texture. Exceptionally sweet.", "yield_notes": "Moderate, early bearing within 2-3 years", "growing_notes": "Excellent for Humid subtropical subtropical conditions. Small size ideal for home gardens. Heat and humidity tolerant. Dwarf growth habit reduces space requirements.", "availability": "Specialty fruit nurseries Queensland, humid subtropical climates area"}, {"name": "Lemon Gold", "slug": "lemon-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Australia (block-shaped variety)", "traits": "Unique block/square shape, 12-13kg fruit. Yellow skin at maturity.", "flesh_fruit": "Firm, crisp texture. Extraordinarily sweet flavor.", "yield_notes": "Good productivity", "growing_notes": "", "availability": ""}, {"name": "Brinsmead Special", "slug": "brinsmead-special", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Kyogle, Northern NSW/QLD border region. Selected by Bob Brinsmead at Tropical Fruit World", "traits": "Latex-free variety (major advantage). Crisp orange flesh. Chance seedling selection.", "flesh_fruit": "Orange crisp flesh, easy to prepare due to latex-free properties.", "yield_notes": "Crops well in subtropics", "growing_notes": "Outstanding subtropical adaptation. Grows well in humid subtropical climates climate zone. Latex-free makes processing much easier. Best selection from Tropical Fruit World.", "availability": "Daleys Fruit Tree Nursery"}, {"name": "Cosmic Gold", "slug": "cosmic-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Queensland selection", "traits": "Sweet variety with grafted reliability.", "flesh_fruit": "Yellow/gold flesh with vanilla, banana and mango flavors.", "yield_notes": "Good production", "growing_notes": "humid subtropical climates-suitable. Sweet complex flavor profile. Available as grafted tr